  1	import * as React from 'react';
  2	import { SCALE_PROVISIONER } from '@odf/core/constants';
  3	import {
  4	  getBreakdownByStorageClass,
  5	  ScaleDashboardQuery,
  6	} from '@odf/core/queries';
  7	import { scResource } from '@odf/core/resources';
  8	import { getStackChartStats } from '@odf/ocs/utils';
  9	import {
 10	  BreakdownCardBody,
 11	  getName,
 12	  getSelectOptions,
 13	  getUID,
 14	  StorageClassResourceKind,
 15	  NamespaceModel,
 16	} from '@odf/shared';
 17	import {
 18	  useCustomPrometheusPoll,
 19	  usePrometheusBasePath,
 20	} from '@odf/shared/hooks/custom-prometheus-poll';
 21	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 22	import {
 23	  getInstantVectorStats,
 24	  humanizeBinaryBytes,
 25	  sortInstantVectorStats,
 26	} from '@odf/shared/utils';
 27	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 28	import {
 29	  MenuToggle,
 30	  MenuToggleElement,
 31	  Select,
 32	  SelectList,
 33	  SelectProps,
 34	} from '@patternfly/react-core';
 35	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
 36	import './CapacityCard.scss';
 37	
 38	export const CapacityCard: React.FC<{}> = () => {
 39	  const { t } = useCustomTranslation();
 40	  const [storageClassName, setStorageClassName] = React.useState('');
 41	  const [isOpenBreakdownSelect, setBreakdownSelect] = React.useState(false);
 42	
 43	  const {
 44	    [ScaleDashboardQuery.BY_USED]: queryByUsed,
 45	    [ScaleDashboardQuery.TOTAL_USED]: queryTotalUsed,
 46	  } = getBreakdownByStorageClass(storageClassName);
 47	  const [modelByUsed, modelUsedError, modelUsedLoading] =
 48	    useCustomPrometheusPoll({
 49	      query: queryByUsed,
 50	      endpoint: 'api/v1/query' as any,
 51	      basePath: usePrometheusBasePath(),
 52	    });
 53	  const [modelTotalUsed, modelTotalError, modalTotalLoading] =
 54	    useCustomPrometheusPoll({
 55	      query: queryTotalUsed,
 56	      endpoint: 'api/v1/query' as any,
 57	      basePath: usePrometheusBasePath(),
 58	    });
 59	
 60	  const [storageClasses, storageClassesLoaded, storageClassesError] =
 61	    useK8sWatchResource<StorageClassResourceKind[]>(scResource);
 62	
 63	  // eslint-disable-next-line react-hooks/exhaustive-deps
 64	  const scaleStorageClasses =
 65	    storageClassesLoaded && !storageClassesError
 66	      ? storageClasses?.filter((sc) => sc.provisioner === SCALE_PROVISIONER)
 67	      : [];
 68	
 69	  React.useEffect(() => {
 70	    if (scaleStorageClasses.length > 0 && !storageClassName) {
 71	      setStorageClassName(getName(scaleStorageClasses[0]));
 72	    }
 73	  }, [scaleStorageClasses, storageClassName]);
 74	
 75	  const dropdownOptions = scaleStorageClasses.map((sc) => ({
 76	    name: getName(sc),
 77	    id: getUID(sc),
 78	  }));
 79	
 80	  const breakdownSelectItems = getSelectOptions(dropdownOptions);
 81	
 82	  const queriesLoadError = modelUsedError || modelTotalError;
 83	  const dataLoaded = !modelUsedLoading && !modalTotalLoading;
 84	
 85	  const humanize = humanizeBinaryBytes;
 86	  const top6MetricsData = getInstantVectorStats(modelByUsed, 'namespace');
 87	  const top5SortedMetricsData = sortInstantVectorStats(top6MetricsData);
 88	  const top5MetricsStats = getStackChartStats(top5SortedMetricsData, humanize);
 89	  const metricTotal: string = modelTotalUsed?.data?.result?.[0]?.value?.[1];
 90	
 91	  const handleMetricsChange: SelectProps['onSelect'] = (
 92	    _e,
 93	    storageClassNameSelection
 94	  ) => {
 95	    setStorageClassName(storageClassNameSelection as any);
 96	    setBreakdownSelect(!isOpenBreakdownSelect);
 97	  };
 98	
 99	  const onToggleClick = () => {
100	    setBreakdownSelect(!isOpenBreakdownSelect);
101	  };
102	
103	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
104	    <MenuToggle
105	      ref={toggleRef}
106	      onClick={onToggleClick}
107	      isExpanded={isOpenBreakdownSelect}
108	      className="scale-capacity-breakdown-card-header__dropdown"
109	      aria-label={t('Break By Dropdown')}
110	      isFullWidth
111	    >
112	      {storageClassName}
113	    </MenuToggle>
114	  );
115	
116	  return (
117	    <Card>
118	      <CardHeader>
119	        <div className="scale-capacity-breakdown-card__header">
120	          <CardTitle id="breakdown-card-title">
121	            {t('Requested Capacity - Namespace (5)')}
122	          </CardTitle>
123	          <Select
124	            id="breakdown-card-metrics-dropdown"
125	            isOpen={isOpenBreakdownSelect}
126	            selected={storageClassName}
127	            onSelect={handleMetricsChange}
128	            onOpenChange={(isOpen) => setBreakdownSelect(isOpen)}
129	            toggle={toggle}
130	            shouldFocusToggleOnSelect
131	            popperProps={{ width: 'trigger' }}
132	          >
133	            <SelectList>{breakdownSelectItems}</SelectList>
134	          </Select>
135	        </div>
136	      </CardHeader>
137	      <CardBody>
138	        <BreakdownCardBody
139	          capacityUsed={metricTotal}
140	          isLoading={!dataLoaded}
141	          hasLoadError={queriesLoadError}
142	          metricTotal={metricTotal}
143	          top5MetricsStats={top5MetricsStats}
144	          metricModel={NamespaceModel}
145	          humanize={humanize}
146	          isPersistentInternal={true}
147	        />
148	      </CardBody>
149	    </Card>
150	  );
151	};
152	
153	export default CapacityCard;

